// ========================================
// КАЛЬКУЛЯТОР СТОИМОСТИ НЕОНОВОЙ ВЫВЕСКИ
// ========================================

const text = $input.item.json.text || '';
const widthCm = parseInt($input.item.json.width) || 50;
const color = ($input.item.json.color || 'красный').toLowerCase();

// Базовая стоимость: 120 руб/см ширины
const basePrice = widthCm * 120;

// Сложность по длине текста: 50 руб/символ
const complexityPrice = text.length * 50;

// Цветовой коэффициент
const colorMultipliers = {
  'красный': 1.0,
  'red': 1.0,
  'синий': 1.0,
  'blue': 1.0,
  'зеленый': 1.0,
  'green': 1.0,
  'розовый': 1.1,
  'pink': 1.1,
  'белый': 1.15,
  'white': 1.15,
  'теплый белый': 1.2,
  'warm white': 1.2,
  'rgb': 1.3,
  'радужный': 1.3
};

const colorMultiplier = colorMultipliers[color] || 1.0;

// Итоговая стоимость
const totalPrice = (basePrice + complexityPrice) * colorMultiplier;

// Вилка ±10%
const minPrice = Math.round(totalPrice * 0.9 / 100) * 100;
const maxPrice = Math.round(totalPrice * 1.1 / 100) * 100;

// Формируем красивый ответ
const colorName = color.charAt(0).toUpperCase() + color.slice(1);

return {
  json: {
    price_min: minPrice,
    price_max: maxPrice,
    price_range: `${minPrice.toLocaleString('ru-RU')} - ${maxPrice.toLocaleString('ru-RU')} руб.`,
    parameters: {
      text: text,
      width: widthCm,
      color: colorName
    },
    details: `Текст: "${text}", Ширина: ${widthCm}см, Цвет: ${colorName}`,
    formula: `База (${widthCm}см × 120₽) + Сложность (${text.length} симв. × 50₽) × Коэф. цвета (${colorMultiplier})`
  }
};

// Получаем параметры
const text = $input.first().json.text || 'NEON';
const width = $input.first().json.width || 100;
const color = $input.first().json.color || 'pink';
const scene = $input.first().json.scene || 'bar';

// Маппинг сцены на английский
const sceneMap = {
  'бар': 'stylish bar interior with dark walls and ambient lighting',
  'кафе': 'cozy cafe interior with warm atmosphere',
  'улица': 'night city street with brick wall building exterior',
  'витрина': 'modern storefront window display',
  'помещение': 'modern interior room with neutral walls',
  'баннер': 'outdoor advertising banner on city building',
  'ресторан': 'upscale restaurant interior with elegant decor',
  'магазин': 'retail store interior with product displays',
  'офис': 'modern office reception area'
};

// Определяем сцену
let sceneDesc = sceneMap['бар']; // по умолчанию
for (const [key, value] of Object.entries(sceneMap)) {
  if (scene.toLowerCase().includes(key)) {
    sceneDesc = value;
    break;
  }
}

// Если не нашли в маппинге, используем как есть
if (!Object.keys(sceneMap).some(k => scene.toLowerCase().includes(k))) {
  sceneDesc = scene + ' setting';
}

// Маппинг цветов
const colorMap = {
  'красный': 'crimson red',
  'синий': 'electric blue',
  'розовый': 'hot pink',
  'белый': 'pure white',
  'зеленый': 'neon green',
  'rgb': 'rainbow multicolor'
};

const neonColor = colorMap[color.toLowerCase()] || color;

const prompt = `Professional product photography: real LED neon sign reading "${text}" in ${neonColor} glow, mounted on wall in ${sceneDesc}. Sign dimensions approximately ${width}cm wide. Realistic neon lighting effect with soft glow and reflections. High-end commercial photography style, 8K quality.`;

return [{ json: { prompt, text, width, color: neonColor, scene: sceneDesc } }];

// Сохраняем данные для следующих шагов
// KIE возвращает taskId в объекте data
const responseData = $input.item.json.data || $input.item.json;
const taskId = responseData.taskId || responseData.task_id;

if (!taskId) {
  throw new Error('Не получен taskId от KIE API. Ответ сервера: ' + JSON.stringify($input.item.json));
}

// Получаем text и color из предыдущего node
const prevData = $('Build Nano Banana Prompt').item.json;

return {
  json: {
    task_id: taskId, // Сохраняем в нашем формате task_id для удобства
    text: prevData.text,
    color: prevData.color,
    width: prevData.width,
    attempts: 0
  }
};

// ========================================
// ФИНАЛЬНЫЙ РЕЗУЛЬТАТ (KIE AI)
// ========================================

const result = $input.item.json;
const savedData = $('Save Task Data').item.json;

// 1. Проверяем ошибки API
if (result.code !== 200 || result.data?.state === 'fail') {
  throw new Error(`Ошибка генерации KIE: ${result.data?.failMsg || result.message}`);
}

// 2. Достаем URL картинки
// KIE возвращает resultJson как СТРОКУ, которую нужно распарсить
let imageUrl = null;

try {
  if (result.data?.resultJson) {
    const parsedResult = JSON.parse(result.data.resultJson);
    if (parsedResult.resultUrls && parsedResult.resultUrls.length > 0) {
      imageUrl = parsedResult.resultUrls[0];
    }
  }
} catch (e) {
  throw new Error('Не удалось распарсить resultJson от KIE: ' + e.message);
}

if (!imageUrl) {
  throw new Error('Не удалось найти URL изображения в ответе: ' + JSON.stringify(result));
}

return {
  json: {
    success: true,
    image_url: imageUrl,
    text: savedData.text,
    color: savedData.color,
    width: savedData.width,
    message: `✨ Макет готов! Текст: "${savedData.text}", Цвет: ${savedData.color}, Ширина: ${savedData.width}см`
  }
};

// Увеличиваем счетчик попыток
const savedData = $('Save Task Data').item.json;
const attempts = (savedData.attempts || 0) + 1;
const maxAttempts = 24; // 24 * 5 сек = 120 сек максимум (2K генерация может быть дольше)

if (attempts >= maxAttempts) {
  throw new Error('Превышено время ожидания генерации (120 сек)');
}

// Возвращаем данные для повторной проверки
return {
  json: {
    task_id: savedData.task_id,
    text: savedData.text,
    color: savedData.color,
    width: savedData.width,
    attempts: attempts
  }
};

